def parse_subparsers(unparsed_arguments, subparsers):
    parsed_arguments = {}
    remaining_arguments = list(unparsed_arguments)
    for subparser_name, subparser in subparsers.items():
        if subparser_name not in remaining_arguments:
            continue
        try:
            subparser.parse_known_args(remaining_arguments)
            parsed_arguments[subparser_name] = subparser.parse_args(remaining_arguments)
            remaining_arguments = []
        except SystemExit:
            continue
    return parsed_arguments, remaining_arguments

