def simplify(args):
    while True:
        new_args = []
        for i, arg in enumerate(args):
            for j, other in enumerate(args):
                if i != j:
                    if (arg & (arg | other)) == arg:
                        new_args.append(arg)
                        continue
                    if (arg | (arg & other)) == arg:
                        new_args.append(arg)
                        continue
                    if (arg & (~arg | other)) == arg & other:
                        new_args.append(arg & other)
                        continue
                    if (arg | (~arg & other)) == arg | other:
                        new_args.append(arg | other)
                        continue
        if new_args == args:
            break
        args = new_args
    return args

