    key_regex = re.compile(r'^[a-zA-Z_][a-zA-Z_0-9]*$')
    value_regex = re.compile(r'^[a-zA-Z_][a-zA-Z_0-9]*$|^\[.*\]$')
    errors = []
    for key, value in labels.items():
        if not isinstance(key, str):
            errors.append({str(key): 'expected string or bytes-like object'})
        elif not key_regex.match(key):
            errors.append({str(key): f'Label key \'{key}\' does not match the regex {key_regex.pattern}'})

        if not isinstance(value, str) and not isinstance(value, list):
            errors.append({str(value): 'expected string or bytes-like object'})
        elif not value_regex.match(value):
            if isinstance(value, list):
                value = str(value)
            errors.append({str(value): f'Label value \'{value}\' does not match the regex {value_regex.pattern}'})
    if errors:
        raise ValidationError(errors)

