def difference(d1, d2, level=1):
    if level <= 0:
        return d1
    result = {}
    for key in d1:
        if key not in d2:
            result[key] = d1[key]
        elif isinstance(d1[key], dict) and isinstance(d2[key], dict):
            result[key] = difference(d1[key], d2[key], level - 1)
