def adjust_datetime(dt):
    if dt.dst() == timedelta(0):
        return dt
    dtoff = dt.utcoffset() - dt.dst()
    dtdst = dt.dst()
    delta = dtoff - dtdst
    if delta.total_seconds() > 0:
        return dt - delta
    else:
        return dt + delta

