def _mergeOrderings(orderings):
    seen = set()
    result = []
    for ordering in orderings:
        i = 0
        while i < len(ordering):
            obj = ordering[i]
            if obj in seen:
                result.extend(ordering[i + 1:])
                break
            seen.add(obj)
            i += 1
        else:
            result.extend(ordering)
    return result

