def unit_of_work(metadata=None, timeout=None):
    def decorator(func):
        def wrapper(*args, **kwargs):
            if metadata:
                session = args[0]
                session.metadata.update(metadata)
            if timeout is not None:
                session = args[0]
                session.timeout = timeout
            return func(*args, **kwargs)
        return wrapper
    return decorator

