import os

def remove_root_from_path(path, root):
    common_prefix = os.path.commonprefix([path, root])
    if path == common_prefix:
        return path
    elif path.startswith(common_prefix):
        return path[len(common_prefix):]
    else:
        raise Exception(f"'{path}' is not a subpath of '{root}'")

def was_processed(processed, path_name, verbose):
    import os
    absolute_path = os.path.abspath(path_name)
    if absolute_path in processed:
        if verbose:
            print(f"Skipping {path_name} as it has already been processed.")
        return True
    processed.add(absolute_path)
    return False

def polygon_points(vertices):
