def parse_frequency(frequency):
    if frequency in [None, "always"]:
        return None
    try:
        num, unit = frequency.split()
        num = int(num)
        if unit == "weeks":
            return timedelta(weeks=num)
        elif unit == "days":
            return timedelta(days=num)
        elif unit == "hours":
            return timedelta(hours=num)
        elif unit == "minutes":
            return timedelta(minutes=num)
        elif unit == "seconds":
            return timedelta(seconds=num)
        else:
            raise ValueError("Unsupported unit of time")
    except ValueError:
        raise ValueError("Invalid frequency string")

def transform_paths(find_paths):
    def is_pattern(path):
        return any(path.startswith(prefix) for prefix in ['pp:', 'root:', '[-!+RrPp']))

    return [path if is_pattern(path) else f'sh:**/*{path}*/**' for path in find_paths]

def run_subprocess(func, *args, extra_env=None):
    import importlib
    import subprocess
    module_name = func.__module__
    module = importlib.import_module(module_name)
    func = module.__dict__[func.__name__]
    cmd = [func.__name__] + [str(arg) for arg in args]
    if extra_env:
        env = dict(os.environ)
        env.update(extra_env)
        return subprocess.run(cmd, env=env)
    else:
        return subprocess.run(cmd)

def process_string_list(input_list):
    if not isinstance(input_list, list):
        return []
    if input_list is None:
        return []
    result = []
    for item in input_list:
        if not isinstance(item, str):
            raise TypeError('Input list must contain only strings')
        if len(item) >= 2 and item.endswith(os.sep):
            result.append(item[:-1])
        else:
            result.append(item)
    return result

def convert_to_regex(pattern):
