    return re.escape(pattern)

def execute_command(command, cwd=None):
    import subprocess
    if cwd is None:
        cwd = '.'
    try:
        process = subprocess.Popen(command, cwd=cwd, shell=False, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        output, error = process.communicate()
        if process.returncode != 0:
            raise Exception(f"Command failed with return code {process.returncode}. Error: {error.decode('utf-8')}")
        return output.decode('utf-8')
    except Exception as e:
        raise Exception(f"An error occurred while executing the command: {str(e)}")

import logging
import logging.config
import yaml

def load_and_validate_configs(config_filenames):
    parsed_configs = {}
    parse_errors = []
    logging.config.dictConfig({
        'version': 1,
        'formatters': {
            'default': {
                'format': '[%(asctime)s] %(levelname)s in %(module)s: %(message)s',
            }
        },
        'handlers': {
            'console': {
                'class': 'logging.StreamHandler',
                'level': 'INFO',
                'formatter': 'default',
            },
        },
        'root': {
            'level': 'INFO',
            'handlers': ['console'],
        },
    })
    logger = logging.getLogger()

    for filename in config_filenames:
        try:
            with open(filename, 'r') as file:
                config = yaml.safe_load(file)
                parsed_configs[filename] = config
        except yaml.YAMLError as e:
            logger.error(f'Error parsing {filename}: line {e.lineno}, {e.problem}')
            parse_errors.append(logging.LogRecord(
                name='root',
                level=logging.ERROR,
                pathname=filename,
                lineno=e.lineno,
                msg=f'Error parsing {filename}: {e.problem}',
                args=None,
                exc_info=None,
            ))

    return parsed_configs, parse_errors

def split_file(file_path, before, after):
    import re
    with open(file_path, 'r') as file:
        content = file.read()
    pattern = re.compile(r'[^' + before + ']+|' + after)
    return pattern.split(content)

def dict_insert(dic, val, key, *keys):
    key_list = key.split('.') + list(keys)
    for k in key_list[:-1]:
        if k not in dic:
            dic[k] = {}
        dic = dic[k]
    dic[key_list[-1]] = val

