def resolve_include_dict(self, spec_file):
    if 'spec_dict' in spec_file and 'shared_groups' in spec_file['spec_dict']:
        include_groups = spec_file['spec_dict']['shared_groups']
        resolved_groups = {}
        for group in include_groups:
            if 'title' in group:
                title = group['title']
                resolved_groups[title] = {}
                for key, value in group.items():
                    if key != 'title':
                        resolved_groups[title][key] = value
        spec_file['spec_dict']['include_groups'] = resolved_groups
        self.spec_dict = spec_file['spec_dict']

def resolve_args(spec, env):
    resolved_args = {}
    for key, value in spec.items():
        if isinstance(value, dict):
            env_key = f"IR_{key.upper()}"
            if env.get(env_key):
                resolved_args[key] = env[env_key]
            elif 'default' in value:
                resolved_args[key] = value['default']
            else:
                resolved_args[key] = ''
        else:
            resolved_args[key] = value
    return resolved_args

