def check_argument_length(args, spec):
    for key, value in args.items():
        if key in spec:
            spec_option = spec[key]
            if 'type' in spec_option and spec_option['type'] in ['list', 'tuple']:
                if len(value) > spec_option['length']:
                    return False
            elif 'type' in spec_option and spec_option['type'] == 'string':
                if len(str(value)) > spec_option['length']:
                    return False
            else:
                return False
    return True

def check_choice(args, spec_helper):
    spec_option = spec_helper.get_parser_option_specs()
    for parser_name, parser_args in args.items():
        for arg_name, arg_value in parser_args.items():
            if arg_name in spec_option and 'choices' in spec_option[arg_name]:
                if arg_value not in spec_option[arg_name]['choices']:
                    return False
    return True

def validate_args(args, spec_option):
    import exceptions
    minimum = spec_option.get('minimum')
    maximum = spec_option.get('maximum')
    if minimum and maximum:
        if not all(minimum <= arg <= maximum for arg in args.values()):
            raise exceptions.ValueError('Arguments are out of range')
    return True

