def extend_vars_dict(vars_dict, extra_vars):
    for extra_var in extra_vars:
        if extra_var.startswith('@'):
            with open(extra_var[1:], 'r') as f:
                extra_var = f.read()
        if '=' in extra_var:
            key, value = extra_var.split('=', 1)
            vars_dict[key] = value
        else:
            dict_merge(vars_dict, {extra_var: ''}, resolver=unique_append_list_resolver)

