def is_diaspora_request(payload, decode_if_bytes=True):
    MAGIC_ENV_TAG = 'diaspora:encrypted_magic_envelope'
    if isinstance(payload, bytes):
        payload = payload.decode('utf-8', errors='replace') if decode_if_bytes else payload
    try:
        payload = json.loads(payload)
    except json.JSONDecodeError:
        try:
            import xml.etree.ElementTree as ET
            root = ET.fromstring(payload)
            return root.tag == MAGIC_ENV_TAG
        except ET.ParseError:
            return False
    return 'encrypted_magic_envelope' in payload

