def find_tags(text, replacer=None):
    lines = text.split('\n')
    code_block = False
    tags = set()
    replaced_text = ''
    for line in lines:
        if code_block:
            if line.strip().startswith('endcode'):
                code_block = False
            replaced_text += line + '\n'
        elif line.strip().startswith('code:'):
            code_block = True
            replaced_text += line + '\n'
        else:
            words = line.split()
            for word in words:
                if word not in ['code:', 'endcode']:
                    if replacer and word in tags:
                        word = replacer(word)
                    tags.add(word)
                    replaced_text += word + ' '
            replaced_text += '\n'
    return tags, replaced_text.strip()

