import hashlib
import rsa
from xml.etree import ElementTree as ET

def verify_signed_xml(xml_string, public_key):
    try:
        root = ET.fromstring(xml_string)
        signature = root.find('.//{http://www.w3.org/2000/09/xmldsig#}Signature').find('.//{http://www.w3.org/2000/09/xmldsig#}SignatureValue').text
        signed_data = ET.tostring(root, encoding='unicode')
        public_key.verify(hashlib.sha1(signed_data.encode()).digest(), bytes.fromhex(signature))
        return True
    except Exception as e:
        return str(e)

import json
import xml.etree.ElementTree as ET
from urllib.parse import urlparse

def parse_webfinger(webfinger_data):
    if webfinger_data.startswith('{'):
        return json.loads(webfinger_data)
    elif webfinger_data.startswith('<'):
        root = ET.fromstring(webfinger_data)
        result = {}
        for identity in root.findall('.//Identity'):
            result['subject'] = identity.attrib['text']
            result['links'] = []
            for link in identity.findall('.//Link'):
                result['links'].append({
                    'rel': link.attrib['rel'],
                    'type': link.attrib['type'],
                    'href': link.attrib['href']
                })
        return result
    else:
        raise ValueError('Invalid webfinger data format')

