import requests

def send_document(url, data, timeout=10, method='post'):
    try:
        response = requests.post(url, data=data, timeout=timeout, **{'method': method}) if method == 'post' else requests.request(method, url, data=data, timeout=timeout)
        return response.status_code, None
    except requests.RequestException as e:
        return None, e
